12	  const startedAt = new Date().toISOString();
13	
14	  setSiteRunProgress({
15	    siteId: site.id, runId, status: "running",
16	    startedAt, updatedAt: startedAt,
17	    visited: 0, total: site.crawl.maxPages,
18	  });
