20	  const runDir = path.join("data", "sites", site.id, "runs", runId);
21	  fs.mkdirSync(runDir, { recursive: true });
22	
23	  const browser = await launchBrowser();
24	  const context = await newSiteContext(browser, {
25	    storageStatePath: site.storageStatePath,
26	    viewport: site.visual.viewport,
27	  });
28	  const page = await context.newPage();
29	
30	  const crawlPage: CrawlPage = {
31	    async goto(url) {
32	      try {
33	        const response = await page.goto(url, { waitUntil: "load" });
34	        return response ? { status: () => response.status(), url: () => page.url() } : null;
35	      } catch {
36	        return null;
37	      }
38	    },
39	    async getLinks() {
40	      return page.$$eval("a[href]", (as) => (as as HTMLAnchorElement[]).map((a) => a.href));
41	    },
42	    url() { return page.url(); },
43	  };
44	
45	  const pages: SitePageCapture[] = [];
46	  let pageIndex = 0;
47	
48	  const captureCurrent = async (record: VisitRecord): Promise<void> => {
49	    pageIndex += 1;
50	    const fileBase = `page-${String(pageIndex).padStart(3, "0")}`;
51	
52	    const screenshotPath = site.visual.enabled
53	      ? path.join(runDir, `${fileBase}.png`)
54	      : undefined;
55	    if (screenshotPath) {
56	      await captureMasked(page, site.visual, screenshotPath);
57	    }
58	
59	    let domHash = "";
60	    let domSerialized = "";
61	    if (site.dom.enabled) {
62	      domSerialized = await page.evaluate(BROWSER_NORMALIZE_FN, site.dom);
63	      domHash = createHash("sha256").update(domSerialized).digest("hex");
64	    }
65	
66	    pages.push({
67	      url: record.url,
68	      finalUrl: record.finalUrl,
69	      httpStatus: record.httpStatus,
70	      domHash, domSerialized,
71	      screenshotPath: screenshotPath ? path.relative(process.cwd(), screenshotPath) : undefined,
72	      capturedAt: new Date().toISOString(),
73	    });
74	
75	    updateSiteRunProgress(site.id, (p) => ({
76	      ...p, visited: pages.length, currentUrl: record.url,
77	      updatedAt: new Date().toISOString(),
78	    }));
79	  };
80	
81	  let outcome;
82	  try {
83	    outcome = await crawl(crawlPage, site.crawl, captureCurrent);
84	  } finally {
85	    await context.close();
86	    await browser.close();
87	  }
88	
89	  const finishedAt = new Date().toISOString();
90	  const status: SiteRunResult["status"] = outcome.errors.length > 0 ? "partial" : "completed";
91	
92	  const result: SiteRunResult = {
93	    runId, siteId: site.id, startedAt, finishedAt, status,
94	    pages, errors: outcome.errors,
95	  };
96	
97	  fs.writeFileSync(
98	    path.join("data", "sites", site.id, "runs", `${runId}.json`),
99	    JSON.stringify(result, null, 2),
100	    "utf-8"
101	  );
102	
103	  updateSiteRunProgress(site.id, (p) => ({ ...p, status: "completed", updatedAt: finishedAt }));
104	
105	  return result;
106	}
