108	const BROWSER_NORMALIZE_FN = (config: { ignoreSelectors: string[]; normalizeWhitespace: boolean }) => {
109	  const ID_ATTRS = new Set([
110	    "aria-describedby", "aria-labelledby", "aria-controls", "aria-owns", "id", "for",
111	  ]);
112	  const ID_RE = /-?[a-z0-9]{6,}/gi;
113	
114	  const doc = document.cloneNode(true) as Document;
115	  doc.querySelectorAll("script, style, noscript").forEach((n) => n.remove());
116	  for (const sel of config.ignoreSelectors) {
117	    doc.querySelectorAll(sel).forEach((n) => n.remove());
118	  }
119	
120	  const walk = (node: Element | null): void => {
121	    if (!node) return;
122	    if (node.attributes) {
123	      const attrs = Array.from(node.attributes);
124	      const sorted = attrs
125	        .map((a) => ({
126	          name: a.name,
127	          value: ID_ATTRS.has(a.name) ? a.value.replace(ID_RE, "<id>") : a.value,
128	        }))
129	        .sort((x, y) => x.name.localeCompare(y.name));
130	      for (const a of attrs) node.removeAttribute(a.name);
131	      for (const { name, value } of sorted) node.setAttribute(name, value);
132	    }
133	    for (const child of Array.from(node.childNodes)) {
134	      if (child.nodeType === 3 && config.normalizeWhitespace) {
135	        child.textContent = (child.textContent ?? "").replace(/\s+/g, " ").trim();
136	      } else if (child.nodeType === 1) {
137	        walk(child as Element);
138	      }
139	    }
140	  };
141	
142	  walk(doc.body);
143	  return doc.body ? doc.body.outerHTML : "";
144	};
